SELECT T.REQUEST_KEY, TO_CHAR(T.CRET_DT, 'YYYY-MM-DD HH24:MI:SS') AS CRET_DT, T.FORM_TYPE_CD, T.OPER_TYPE_CD, T.PROC_CD, T.CSTMR_NM, T.CSTMR_BIRTH, T.CSTMR_TYPE_CD, T.IDENTITY_CERT_TYPE_CD, T.AGENT_CD, T.AGENT_NM, T.SHOP_CD, T.SHOP_NM, T.MANAGER_NM, T.REGST_ID, T.AMD_ID, T.MEMO, T.CONTRACT_NUM, T.CANCEL_MOBILE_NO, T.RES_CD, T.RES_MSG, T.RES_NO FROM (
) T WHERE 1 = 1
AND T.FORM_TYPE_CD = #{formTypeCd}
AND T.PROC_CD = #{procCd}
AND T.CONTRACT_NUM = #{searchName} AND T.CANCEL_MOBILE_NO = #{searchName} AND T.CSTMR_NM LIKE '%' || #{searchName} || '%'
AND TO_CHAR(T.CRET_DT, 'YYYYMMDD') >= #{startDt}
AND TO_CHAR(T.CRET_DT, 'YYYYMMDD') <= #{endDt}
ORDER BY T.CRET_DT DESC
LIMIT #{page.rowSize} OFFSET (#{page.pageNum} - 1) * #{page.rowSize}

